mapper.select:
SELECT * FROM ( SELECT
FROM `ir_profile`.`courts` c LEFT JOIN `ir_auth`.`users` u ON u.`id` = c.`created_by` WHERE c.`status` = 0
AND c.`approval_status` IN ('voided', 'rejected')
AND c.`approval_status` = #{status}
UNION ALL
SELECT r.`court_id` AS `id`, r.`name`, r.`address`, r.`country`, r.`province`, r.`city`, 'pending_review' AS `venue_status`, r.`request_status` AS `approval_status`, r.`wechat_mini_program_name`, r.`photo_urls`, r.`description`, r.`submitted_by` AS `created_by`, r.`reviewed_by`, r.`reviewed_at`, r.`rejected_reason`, u.`email` AS submitter_email, u.`display_name` AS submitter_name, u.`phone` AS submitter_phone FROM `ir_profile`.`court_change_requests` r LEFT JOIN `ir_auth`.`users` u ON u.`id` = r.`submitted_by` WHERE r.`status` = 0
AND r.`request_status` = 'voided'
AND r.`request_status` = #{status}
) review_rows ORDER BY CASE `approval_status` WHEN 'pending' THEN 0 WHEN 'approved' THEN 1 WHEN 'voided' THEN 2 WHEN 'blacklisted' THEN 3 ELSE 4 END, `reviewed_at` DESC, `name` ASC
